python3 -c "
import json
with open('/home/halei/.openclaw/openclaw.json', 'r') as f:
    config = json.load(f)

# Check the full structure to find where capability-evolver is
def find_key(obj, key, path=''):
    if isinstance(obj, dict):
        for k, v in obj.items():
            if k == key:
                print(f'Found at: {path}.{k}')
                print(f'Value: {v}')
                return
            find_key(v, key, f'{path}.{k}')
    elif isinstance(obj, list):
        for i, item in enumerate(obj):
            find_key(item, key, f'{path}[{i}]')

find_key(config, 'capability-evolver')
"

